from functools import wraps
from jwt import decode, ExpiredSignatureError, InvalidTokenError
import jwt
from flask import current_app, request, jsonify
from flask_jwt_extended import JWTManager, create_access_token, jwt_required, get_raw_jwt

def multiple_algorithms_wrapper(algorithm):
    def decorator(view_function):
        @wraps(view_function)
        def wrapper(*args, **kwargs):
            try:
                token = None
                if 'Authorization' in request.headers:
                    token = request.headers['Authorization'].split(' ')[1]
                elif 'jwt' in request.cookies:
                    token = request.cookies['jwt']
                else:
                    return jsonify({"error": "Token not found"}), 401

                if algorithm == 'HS256':
                    secret_key = current_app.config['SECRET_KEY']
                elif algorithm == 'RS256':
                    try:
                        key_id = jwt.get_header(token)['kid']
                        public_key = jwt.get_public_key(key_id, current_app.config['PUBLIC_KEYS'])
                    except Exception as e:
                        return jsonify({"error": str(e)}), 401
                else:
                    raise ValueError(f"Invalid algorithm: {algorithm}")

                decoded_token = decode(token, key=secret_key if algorithm == 'HS256' else public_key, algorithms=[algorithm])
                view_function(*args, **kwargs, user=decoded_token)
            except (ExpiredSignatureError, InvalidTokenError) as e:
                return jsonify({"error": str(e)}), 401
            except Exception as e:
                return jsonify({"error": str(e)}), 500
        return wrapper
    return decorator

